package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.bind.TreeTypeAdapter;
import com.google.gson.internal.bind.TypeAdapters;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import java.lang.reflect.Field;
import java.lang.reflect.Type;
import java.util.List;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void registerTypeHierarchyAdapter_withNullBaseType_throwsNullPointerException() {
    assertThrows(NullPointerException.class, () -> gsonBuilder.registerTypeHierarchyAdapter(null, new JsonSerializer<Object>() {
      @Override
      public JsonElement serialize(Object src, Type typeOfSrc, JsonSerializationContext context) {
        return null;
      }
    }));
  }

  @Test
  void registerTypeHierarchyAdapter_withInvalidTypeAdapter_throwsIllegalArgumentException() {
    Object invalidAdapter = new Object();
    assertThrows(IllegalArgumentException.class,
        () -> gsonBuilder.registerTypeHierarchyAdapter(String.class, invalidAdapter));
  }

  @Test
  void registerTypeHierarchyAdapter_withJsonSerializer_addsToHierarchyFactories() throws Exception {
    Class<?> baseType = Number.class;
    JsonSerializer<String> serializer = mock(JsonSerializer.class);

    try (MockedStatic<TreeTypeAdapter> treeTypeAdapterStatic = Mockito.mockStatic(TreeTypeAdapter.class)) {
      TypeAdapterFactory factoryMock = mock(TypeAdapterFactory.class);
      treeTypeAdapterStatic.when(() -> TreeTypeAdapter.newTypeHierarchyFactory(baseType, serializer))
          .thenReturn(factoryMock);

      GsonBuilder returned = gsonBuilder.registerTypeHierarchyAdapter(baseType, serializer);

      assertSame(gsonBuilder, returned);

      // Verify hierarchyFactories contains the factoryMock
      Field hierarchyFactoriesField = GsonBuilder.class.getDeclaredField("hierarchyFactories");
      hierarchyFactoriesField.setAccessible(true);
      List<?> hierarchyFactories = (List<?>) hierarchyFactoriesField.get(gsonBuilder);
      assertTrue(hierarchyFactories.contains(factoryMock));
    }
  }

  @Test
  void registerTypeHierarchyAdapter_withJsonDeserializer_addsToHierarchyFactories() throws Exception {
    Class<?> baseType = Integer.class;
    JsonDeserializer<String> deserializer = mock(JsonDeserializer.class);

    try (MockedStatic<TreeTypeAdapter> treeTypeAdapterStatic = Mockito.mockStatic(TreeTypeAdapter.class)) {
      TypeAdapterFactory factoryMock = mock(TypeAdapterFactory.class);
      treeTypeAdapterStatic.when(() -> TreeTypeAdapter.newTypeHierarchyFactory(baseType, deserializer))
          .thenReturn(factoryMock);

      GsonBuilder returned = gsonBuilder.registerTypeHierarchyAdapter(baseType, deserializer);

      assertSame(gsonBuilder, returned);

      Field hierarchyFactoriesField = GsonBuilder.class.getDeclaredField("hierarchyFactories");
      hierarchyFactoriesField.setAccessible(true);
      List<?> hierarchyFactories = (List<?>) hierarchyFactoriesField.get(gsonBuilder);
      assertTrue(hierarchyFactories.contains(factoryMock));
    }
  }

  @Test
  void registerTypeHierarchyAdapter_withTypeAdapter_addsToFactories() throws Exception {
    Class<?> baseType = Double.class;
    @SuppressWarnings("unchecked")
    TypeAdapter<String> typeAdapter = mock(TypeAdapter.class);

    try (MockedStatic<TypeAdapters> typeAdaptersStatic = Mockito.mockStatic(TypeAdapters.class)) {
      TypeAdapterFactory factoryMock = mock(TypeAdapterFactory.class);
      typeAdaptersStatic.when(() -> TypeAdapters.newTypeHierarchyFactory(baseType, typeAdapter))
          .thenReturn(factoryMock);

      GsonBuilder returned = gsonBuilder.registerTypeHierarchyAdapter(baseType, typeAdapter);

      assertSame(gsonBuilder, returned);

      Field factoriesField = GsonBuilder.class.getDeclaredField("factories");
      factoriesField.setAccessible(true);
      List<?> factories = (List<?>) factoriesField.get(gsonBuilder);
      assertTrue(factories.contains(factoryMock));
    }
  }

  @Test
  void registerTypeHierarchyAdapter_withJsonSerializerAndTypeAdapter_addsToBothLists() throws Exception {
    Class<?> baseType = Long.class;

    // Create a mock that implements both JsonSerializer and TypeAdapter
    Object adapter = new JsonSerializer<Object>() {
      @Override
      public JsonElement serialize(Object src, Type typeOfSrc, JsonSerializationContext context) {
        return null;
      }
    };

    // Create a spy TypeAdapter to also pass instanceof check
    @SuppressWarnings("unchecked")
    TypeAdapter<Object> typeAdapter = mock(TypeAdapter.class);

    Object combinedAdapter = new Object() implements JsonSerializer<Object>, JsonDeserializer<Object>, TypeAdapter<Object> {
      @Override
      public JsonElement serialize(Object src, Type typeOfSrc, JsonSerializationContext context) {
        return null;
      }
      @Override
      public Object deserialize(JsonElement json, Type typeOfT, JsonDeserializationContext context) {
        return null;
      }
      @Override
      public Object read(com.google.gson.stream.JsonReader in) {
        return null;
      }
      @Override
      public void write(com.google.gson.stream.JsonWriter out, Object value) {
      }
    };

    // Because this combinedAdapter is anonymous, use reflection to create a proxy or just test separately

    // Instead, test separately for serializer and type adapter

    // Test JsonSerializer and TypeAdapter separately

    // JsonSerializer part
    JsonSerializer<Object> serializer = mock(JsonSerializer.class);
    // TypeAdapter part
    @SuppressWarnings("unchecked")
    TypeAdapter<Object> adapterMock = mock(TypeAdapter.class);

    // We will test with serializer instance that also is a TypeAdapter by casting (unsafe but for test)
    // So create a proxy object that passes instanceof checks

    Object proxyAdapter = new Object() implements JsonSerializer<Object>, TypeAdapter<Object> {
      @Override
      public JsonElement serialize(Object src, Type typeOfSrc, JsonSerializationContext context) {
        return null;
      }
      @Override
      public Object read(com.google.gson.stream.JsonReader in) {
        return null;
      }
      @Override
      public void write(com.google.gson.stream.JsonWriter out, Object value) {
      }
    };

    try (MockedStatic<TreeTypeAdapter> treeTypeAdapterStatic = Mockito.mockStatic(TreeTypeAdapter.class);
         MockedStatic<TypeAdapters> typeAdaptersStatic = Mockito.mockStatic(TypeAdapters.class)) {
      TypeAdapterFactory hierarchyFactory = mock(TypeAdapterFactory.class);
      TypeAdapterFactory factory = mock(TypeAdapterFactory.class);

      treeTypeAdapterStatic.when(() -> TreeTypeAdapter.newTypeHierarchyFactory(baseType, proxyAdapter))
          .thenReturn(hierarchyFactory);
      typeAdaptersStatic.when(() -> TypeAdapters.newTypeHierarchyFactory(baseType, (TypeAdapter<?>) proxyAdapter))
          .thenReturn(factory);

      GsonBuilder returned = gsonBuilder.registerTypeHierarchyAdapter(baseType, proxyAdapter);

      assertSame(gsonBuilder, returned);

      Field hierarchyFactoriesField = GsonBuilder.class.getDeclaredField("hierarchyFactories");
      hierarchyFactoriesField.setAccessible(true);
      List<?> hierarchyFactories = (List<?>) hierarchyFactoriesField.get(gsonBuilder);
      assertTrue(hierarchyFactories.contains(hierarchyFactory));

      Field factoriesField = GsonBuilder.class.getDeclaredField("factories");
      factoriesField.setAccessible(true);
      List<?> factories = (List<?>) factoriesField.get(gsonBuilder);
      assertTrue(factories.contains(factory));
    }
  }
}
